import{_ as a,H as e,f as i,i as o}from"./chunks/framework.DbTCwA-u.js";const m=JSON.parse('{"title":"Установка и требования","description":"Узнайте, как установить EligiusNametag на ваш сервер Paper или Folia.","frontmatter":{"title":"Установка и требования","description":"Узнайте, как установить EligiusNametag на ваш сервер Paper или Folia."},"headers":[],"relativePath":"ru/installation.md","filePath":"ru/installation.md"}'),l={name:"ru/installation.md"};function r(n,t,s,d,c,g){return e(),i("div",null,[...t[0]||(t[0]=[o('<h1 id="установка-и-требования" tabindex="-1">Установка и требования <a class="header-anchor" href="#установка-и-требования" aria-label="Permalink to &quot;Установка и требования&quot;">​</a></h1><p>EligiusNametag — это современный и мощный плагин. Используя новейшие возможности Minecraft Text API и многопоточность, он требует обновленной среды.</p><h2 id="📋-системные-требования" tabindex="-1">📋 Системные требования <a class="header-anchor" href="#📋-системные-требования" aria-label="Permalink to &quot;📋 Системные требования&quot;">​</a></h2><table tabindex="0"><thead><tr><th>Требование</th><th>Минимальная версия</th><th>Причина</th></tr></thead><tbody><tr><td><strong>Платформа</strong></td><td>Paper 1.21 или Folia 1.21+</td><td>Строгое использование компонентов <code>TEXT_DISPLAY</code> и команд Brigadier.</td></tr><tr><td><strong>Java</strong></td><td>Java 21 LTS</td><td>Исходный код скомпилирован в формате JDK 21.</td></tr></tbody></table><h2 id="📦-зависимости" tabindex="-1">📦 Зависимости <a class="header-anchor" href="#📦-зависимости" aria-label="Permalink to &quot;📦 Зависимости&quot;">​</a></h2><p>У вас должны быть установлены следующие плагины в папке <code>plugins/</code>:</p><ol><li><strong>ProtocolLib</strong> <em>(Обязательно)</em>: Используется для невидимой отправки пакетов голограмм без расхода физических TPS.</li><li><strong>Vault</strong> <em>(Опционально)</em>: Если вы хотите назначать определенные дизайны неймтегов в зависимости от ранга пользователя (Admin, VIP и т.д.).</li><li><strong>PlaceholderAPI</strong> <em>(Опционально)</em>: Для обработки внешних переменных, таких как статистика, деньги или кланы в неймтегах.</li><li><strong>ItemsAdder</strong> <em>(Опционально)</em>: Для отображения пользовательских эмодзи в именах.</li></ol><h2 id="🚀-шаги-установки" tabindex="-1">🚀 Шаги установки <a class="header-anchor" href="#🚀-шаги-установки" aria-label="Permalink to &quot;🚀 Шаги установки&quot;">​</a></h2><ol><li>Скачайте файл <code>EligiusNametag-1.x.x.jar</code> на вкладке <strong>Releases</strong>.</li><li>Скопируйте файл в папку <code>plugins/</code> вашего сервера.</li><li>Убедитесь, что у вас установлен <strong>ProtocolLib</strong>.</li><li>Запустите ваш сервер.</li><li>Вы увидите анимацию запуска в консоли с котом Eligius MC, подтверждающим успешное подключение плагина.</li><li>Готово! Вы можете настроить всё в папке <code>plugins/EligiusNametag/</code>.</li></ol>',9)])])}const u=a(l,[["render",r]]);export{m as __pageData,u as default};
